                this.posting = false;
                this.tryingToPlot = false;
                // Reset cache so next plot will definitely execute when turns are populated
                this.lastSimulatedInputs = "";
                this.lastSimulatedMagnetics = "";
                this.lastForceUpdate = 0;
                return;
            }

            try {
